import React, { useState } from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import TestimonialCard from "./TestimonialCard";
import { motion } from "framer-motion";

const testimonials = [
  { id: 1, name: "Anonymous", rating: 5, text: `I am constantly running with 3 kids &...`, img: "/media/aboutus/testimonial1.jpg" },
  { id: 2, name: "Kristi", rating: 5, text: `I started to replace my afternoon cup of coffee...`, img: "/media/aboutus/testimonial2.jpg" },
  { id: 3, name: "Anonymous", rating: 5, text: `I hate water but since finding Hydrant...`, img: "/media/aboutus/testimonial3.jpg" },
  { id: 4, name: "User4", rating: 5, text: `Great product!`, img: "/media/aboutus/testimonial1.jpg" },
  { id: 5, name: "User5", rating: 5, text: `Super refreshing.`, img: "/media/aboutus/testimonial2.jpg" },
  { id: 6, name: "User6", rating: 5, text: `Helps me focus all day.`, img: "/media/aboutus/testimonial3.jpg" },
  { id: 7, name: "User7", rating: 5, text: `My skin looks hydrated and radiant.`, img: "/media/aboutus/testimonial1.jpg" },
];

const PersonalSection = () => {
  // Mantener el estado del índice clickeado para agrandar esa tarjeta
  const [activeIndex, setActiveIndex] = useState(null);

  return (
    <section
      style={{
        maxWidth: "1400px",
        margin: "0 auto",
        marginBottom: "6rem",
        padding: "0 2rem",
      }}
    >
      <h2
        style={{
          fontWeight: "900",
          fontSize: "3rem",
          textAlign: "center",
          marginBottom: "2rem",
          color: "#003E73",
        }}
      >
        Loved by thousands
      </h2>

      <Swiper
        slidesPerView={7}
        spaceBetween={20}
        breakpoints={{
          320: { slidesPerView: 1, spaceBetween: 10 },
          640: { slidesPerView: 3, spaceBetween: 15 },
          1024: { slidesPerView: 5, spaceBetween: 20 },
          1400: { slidesPerView: 7, spaceBetween: 25 },
        }}
        style={{ paddingBottom: "3rem" }}
      >
        {testimonials.map((t, idx) => (
          <SwiperSlide
            key={t.id}
            style={{ display: "flex", justifyContent: "center" }}
          >
            <motion.div
              onClick={() => setActiveIndex(idx === activeIndex ? null : idx)}
              whileHover={{ backgroundColor: "#d0e6db", scale: 1.05 }}
              animate={{
                scale: idx === activeIndex ? 1.1 : 1,
                backgroundColor: idx === activeIndex ? "#caffbf" : "inherit",
              }}
              transition={{ type: "spring", stiffness: 300, damping: 20 }}
              style={{ borderRadius: "1rem", width: "100%", cursor: "pointer" }}
            >
              <TestimonialCard testimonial={t} index={idx} />
            </motion.div>
          </SwiperSlide>
        ))}
      </Swiper>
    </section>
  );
};

export default PersonalSection;
